# WebSocket server implementation for ESP32 using MicroPython

class WebSocketServer:
    def __init__(self, host='0.0.0.0', port=8765):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)
        self.clients = []

    def start(self):
        print(f"WebSocket server started on {self.host}:{self.port}")
        while True:
            client_sock, addr = self.server_socket.accept()
            print(f"New connection from {addr}")
            asyncio.create_task(self.handle_client(client_sock))

    async def handle_client(self, client_sock):
        try:
            await self.handshake(client_sock)
            while True:
                data = await self.read_data(client_sock)
                if not data:
                    break
                message = data.decode('utf-8')
                print(f"Received: {message}")
                # Process JSON command here
                response = {"status": "success"}
                await self.send_message(client_sock, response)
        except Exception as e:
            print(f"Error: {e}")
        finally:
            client_sock.close()
            self.clients.remove(client_sock)

    async def handshake(self, client_sock):
        request = client_sock.recv(1024).decode('utf-8')
        headers = request.split('\r\n')
        for header in headers:
            if 'Sec-WebSocket-Key' in header:
                key = header.split(': ')[1].strip()
                response = (
                    "HTTP/1.1 101 Switching Protocols\r\n"
                    "Upgrade: websocket\r\n"
                    "Connection: Upgrade\r\n"
                    f"Sec-WebSocket-Accept: {self.generate_response_key(key)}\r\n\r\n"
                )
                client_sock.sendall(response.encode('utf-8'))
                break

    def generate_response_key(self, key):
        import hashlib
        import base64
        magic_string = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        combined = (key + magic_string).encode('utf-8')
        return base64.b64encode(hashlib.sha1(combined).digest()).decode('utf-8')

    async def read_data(self, client_sock):
        try:
            data = await self.read_until(client_sock, b'\x00')
            if not data:
                return None
            length = int.from_bytes(data[1:2], 'big') & 0x7F
            if length == 126:
                length = int.from_bytes(data[2:4], 'big')
            elif length == 127:
                length = int.from_bytes(data[2:10], 'big')
            mask = data[2 + length:]
            payload = bytearray()
            for i in range(length):
                payload.append(data[2 + i] ^ mask[i % 4])
            return payload
        except Exception as e:
            print(f"Error reading data: {e}")
            return None

    async def read_until(self, client_sock, delimiter):
        buffer = bytearray()
        while True:
            data = await self.read_data(client_sock)
            if not data:
                break
            buffer.extend(data)
            if delimiter in buffer:
                index = buffer.index(delimiter)
                result = buffer[:index]
                buffer = buffer[index + len(delimiter):]
                return result
        return None

    async def send_message(self, client_sock, message):
        import json
        payload = json.dumps(message).encode('utf-8')
        length = len(payload)
        header = bytearray([0x81])
        if length < 126:
            header.append(length)
        elif length < 65536:
            header.append(126)
            header.extend(length.to_bytes(2, 'big'))
        else:
            header.append(127)
            header.extend(length.to_bytes(8, 'big'))
        client_sock.sendall(header + payload)

